import java.util.*;

public class TrapezoidCount {
    public static long solve(long[][] points) {
        int n = points.length;
        Map<String, Integer> slopeGroupCount = new HashMap<>();
        Map<String, Map<String, Integer>> slopeGroupDeg = new HashMap<>();
        Map<String, Integer> midGroupCount = new HashMap<>();
        Map<String, Map<String, Integer>> midGroupDeg = new HashMap<>();

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
