                slopeGroupCount.put(slopeKey, slopeGroupCount.getOrDefault(slopeKey, 0) + 1);
                Map<String, Integer> slopeDegMap = slopeGroupDeg.computeIfAbsent(slopeKey, k -> new HashMap<>());
                String p1Key = x1 + "," + y1;
                String p2Key = x2 + "," + y2;
                slopeDegMap.put(p1Key, slopeDegMap.getOrDefault(p1Key, 0) + 1);
                slopeDegMap.put(p2Key, slopeDegMap.getOrDefault(p2Key, 0) + 1);

                long mx = x1 + x2, my = y1 + y2;
                String midKey = mx + "," + my;
                midGroupCount.put(midKey, midGroupCount.getOrDefault(midKey, 0) + 1);
                Map<String, Integer> midDegMap = midGroupDeg.computeIfAbsent(midKey, k -> new HashMap<>());
                midDegMap.put(p1Key, midDegMap.getOrDefault(p1Key, 0) + 1);
                midDegMap.put(p2Key, midDegMap.getOrDefault(p2Key, 0) + 1);
            }
        }

        long sumSlope = 0;
        for (Map.Entry<String, Integer> entry : slopeGroupCount.entrySet()) {
            long k = entry.getValue();
            long totalPairs = k * (k - 1) / 2;
            long subtract = 0;
            Map<String, Integer> degMap = slopeGroupDeg.get(entry.getKey());
            for (int degree : degMap.values()) {
                subtract += (long) degree * (degree - 1) / 2;
            }
            sumSlope += (totalPairs - subtract);
        }

        long parallelogramCount = 0;
        for (Map.Entry<String, Integer> entry : midGroupCount.entrySet()) {
            long k = entry.getValue();
            long totalPairs = k * (k - 1) / 2;
            long subtract = 0;
            Map<String, Integer> degMap = midGroupDeg.get(entry.getKey());
            for (int degree : degMap.values()) {
                subtract += (long) degree * (degree - 1) / 2;
            }
            parallelogramCount += (totalPairs - subtract);
        }

        return sumSlope - parallelogramCount;
    }

    private static String getSlopeKey(long x1, long y1, long x2, long y2) {
        long dx = x2 - x1;
        long dy = y2 - y1;
        if (dx == 0) {
            if (dy == 0) {
                return "0,0";
            }
            return "0,1";
        }
        long a = Math.abs(dx);
        long b = Math.abs(dy);
        long g = gcd(a, b);
        if (g != 0) {
            dx /= g;
            dy /= g;
        }
        if (dx < 0) {
            dx = -dx;
            dy = -dy;
        }
        return dx + "," + dy;
    }

    private static long gcd(long a, long b) {
        a = Math.abs(a);
        b = Math.abs(b);
        if (a == 0) return b;
        if (b == 0) return a;
        while (b != 0) {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}
